namespace sv_60f4fd16bbd8466788f244f4bb700bef.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_60f4fd16bbd8466788f244f4bb700bef.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="row">
    @* ── Left sidebar: filters ── *@
    <div class="col-md-3">
        <div class="card">
            <div class="card-header fw-bold">Filters</div>
            <div class="card-body">
                @* Categories *@
                <h6>Categories</h6>
                @if (categories is not null)
                {
                    @foreach (var cat in categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                   checked="@selectedCategories.Contains(cat)"
                                   @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                        </div>
                    }
                }
                else
                {
                    <p class="text-muted small">Loading…</p>
                }

                <hr />

                @* Price range *@
                <h6>Price Range</h6>
                <div class="mb-2">
                    <label class="form-label small" for="minPrice">Min Price</label>
                    <input id="minPrice" type="number" class="form-control form-control-sm"
                           min="0" step="0.01" placeholder="0"
                           @bind="minPrice" />
                </div>
                <div class="mb-2">
                    <label class="form-label small" for="maxPrice">Max Price</label>
                    <input id="maxPrice" type="number" class="form-control form-control-sm"
                           min="0" step="0.01" placeholder="Any"
                           @bind="maxPrice" />
                </div>

                <hr />

                @* In-stock toggle *@
                <div class="form-check mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly"
                           @bind="inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>

                @* Action buttons *@
                <button class="btn btn-primary w-100 mb-2" @onclick="ApplyFilters">Apply Filters</button>
                <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear Filters</button>
            </div>
        </div>
    </div>

    @* ── Main content area ── *@
    <div class="col-md-9">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
            </div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }
        else if (result is null || result.Items.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products found. Try adjusting your filters.
            </div>
        }
        else
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="form-label small mb-0 me-2" for="sortSelect">Sort by</label>
                    <select id="sortSelect" class="form-select form-select-sm d-inline-block w-auto"
                            @bind="currentSort" @bind:after="OnSortChanged">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A–Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted small">
                    Showing @(StartItem)–@(EndItem) of @result.TotalCount products
                </span>
            </div>

            @* Product grid *@
            <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
                @foreach (var product in result.Items)
                {
                    <div class="col">
                        <ProductCard Product="product"
                                     OnProductSelected="OnProductSelected"
                                     OnAddToCart="OnAddToCart" />
                    </div>
                }
            </div>

            @* Pagination *@
            @if (TotalPages > 1)
            {
                <nav aria-label="Product pagination" class="mt-4">
                    <ul class="pagination justify-content-center">
                        <li class="page-item @(currentPage == 1 ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(currentPage - 1)"
                                    disabled="@(currentPage == 1)">Previous</button>
                        </li>
                        @foreach (var p in PageNumbers)
                        {
                            <li class="page-item @(p == currentPage ? "active" : "")">
                                <button class="page-link" @onclick="() => GoToPage(p)">@p</button>
                            </li>
                        }
                        <li class="page-item @(currentPage == TotalPages ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(currentPage + 1)"
                                    disabled="@(currentPage == TotalPages)">Next</button>
                        </li>
                    </ul>
                </nav>
            }
        }
    </div>
</div>

@code {
    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    private string currentSort = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 9;

    private PagedResult<Product>? result;
    private bool isLoading = true;
    private string? errorMessage;

    // Computed helpers
    private int TotalPages => result is null || result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);

    private int StartItem => result is null ? 0 : (result.Page - 1) * result.PageSize + 1;
    private int EndItem => result is null ? 0 : Math.Min(result.Page * result.PageSize, result.TotalCount);

    private IEnumerable<int> PageNumbers => Enumerable.Range(1, TotalPages);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            // Load categories and first page concurrently
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = SearchProductsAsync();
            categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
            isLoading = false;
        }
    }

    private async Task SearchProductsAsync()
    {
        isLoading = true;
        errorMessage = null;
        StateHasChanged();

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            result = await ProductService.SearchAsync(filter, currentSort, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > TotalPages) return;
        currentPage = page;
        await SearchProductsAsync();
    }

    private void OnProductSelected(Product product)
    {
        // Parent-level handling; extend with NavigationManager if needed
    }

    private void OnAddToCart(Product product)
    {
        // Cart handling placeholder
    }
}

@using sv_60f4fd16bbd8466788f244f4bb700bef.Services

<div class="card h-100 product-card" @onclick="HandleCardClick" role="button">
    <div class="card-img-top bg-light d-flex align-items-center justify-content-center"
         style="height:180px;" title="@Product.Name">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title">@Product.Name</h6>
        <p class="card-text fw-bold mb-1">@Product.Price.ToString("C")</p>
        <p class="card-text mb-2" title="@($"{Product.Rating:F1} out of 5")">
            @RenderStars(Product.Rating)
        </p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string RenderStars(double rating)
    {
        int full = (int)Math.Round(rating);
        int empty = 5 - full;
        return new string('★', full) + new string('☆', empty);
    }
}

.product-card {
    cursor: pointer;
    transition: box-shadow 0.15s ease-in-out;
}

.product-card:hover {
    box-shadow: 0 0.25rem 0.75rem rgba(0, 0, 0, 0.15);
}

