                           @bind="minPrice" />
                </div>
                <div class="mb-2">
                    <label class="form-label small" for="maxPrice">Max Price</label>
                    <input id="maxPrice" type="number" class="form-control form-control-sm"
                           min="0" step="0.01" placeholder="Any"
                           @bind="maxPrice" />
                </div>

                <hr />

                @* In-stock toggle *@
                <div class="form-check mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly"
                           @bind="inStockOnly" />
