    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    private string currentSort = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 9;

    private PagedResult<Product>? result;
    private bool isLoading = true;
    private string? errorMessage;

    // Computed helpers
    private int TotalPages => result is null || result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);

    private int StartItem => result is null ? 0 : (result.Page - 1) * result.PageSize + 1;
    private int EndItem => result is null ? 0 : Math.Min(result.Page * result.PageSize, result.TotalCount);

    private IEnumerable<int> PageNumbers => Enumerable.Range(1, TotalPages);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            // Load categories and first page concurrently
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = SearchProductsAsync();
            categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
            isLoading = false;
        }
    }

    private async Task SearchProductsAsync()
    {
        isLoading = true;
        errorMessage = null;
        StateHasChanged();

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            result = await ProductService.SearchAsync(filter, currentSort, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > TotalPages) return;
        currentPage = page;
        await SearchProductsAsync();
    }

    private void OnProductSelected(Product product)
    {
        // Parent-level handling; extend with NavigationManager if needed
    }

    private void OnAddToCart(Product product)
    {
        // Cart handling placeholder
    }
}
"}

